import styled from 'styled-components';

export const NavContainer = styled.nav`
display:flex;
justify-content:center;
background-color:#50A6D8;
width:20%;

hr {
    width:60%;
}


.links__container {
    list-style:none;
}
a {
    color:rgb(255,255,255);
    text-decoration:none;
}

@media screen and min-width(900px) {
    display:flex;
    flex-direction:row;
    width:100%;
}
`
